#!/bin/bash
# =============================================================================
# {{PROJECT_NAME}} Minimal Claude Code Environment - Post-Create Script
# =============================================================================
# This script sets up a minimal environment optimized for Claude Code execution.
# Generated by devcontainer-generator (Claude-only mode)
# =============================================================================

set -e

LOG_PREFIX="[post-create]"

log() {
    echo "$LOG_PREFIX $1"
}

log "Starting minimal Claude Code setup..."

# -----------------------------------------------------------------------------
# Git Configuration
# -----------------------------------------------------------------------------
log "Configuring Git..."

git config --global credential.helper store
git config --global core.autocrlf input
git config --global init.defaultBranch main
git config --global color.ui auto
git config --global pull.rebase false
git config --global push.autoSetupRemote true

# -----------------------------------------------------------------------------
# Claude Code Installation
# -----------------------------------------------------------------------------
log "Installing Claude Code..."

curl -fsSL https://claude.ai/install.sh | bash || {
    log "  Warning: Claude Code installation failed, continuing..."
}

# Verify installation
if command -v claude &> /dev/null; then
    log "  Claude Code installed: $(claude --version 2>/dev/null || echo 'version unknown')"
elif [[ -x "$HOME/.local/bin/claude" ]]; then
    log "  Claude Code installed to ~/.local/bin"
else
    log "  Warning: Claude Code not found after installation"
fi

# {{INSTALL_CCOMETIXLINE}} - Add if CCometixLine selected:
# log "Installing CCometixLine..."
# npm install -g @cometix/ccline || {
#     log "  Warning: CCometixLine installation failed"
# }
#
# # Configure Claude Code statusline
# mkdir -p ~/.claude
# if [[ ! -f ~/.claude/settings.json ]]; then
#     cat > ~/.claude/settings.json << 'SETTINGS'
# {
#   "statusLine": {
#     "type": "command",
#     "command": "~/.claude/ccline/ccline",
#     "padding": 0
#   }
# }
# SETTINGS
#     log "  CCometixLine configured"
# fi

# -----------------------------------------------------------------------------
# Shell Configuration
# -----------------------------------------------------------------------------
log "Configuring shell..."

# Ensure ~/.local/bin is in PATH
mkdir -p ~/.local/bin 2>/dev/null || sudo mkdir -p ~/.local/bin && sudo chown -R "$(id -u):$(id -g)" ~/.local

if ! grep -q 'export PATH="$HOME/.local/bin:$PATH"' ~/.bashrc 2>/dev/null; then
    echo 'export PATH="$HOME/.local/bin:$PATH"' >> ~/.bashrc
fi
if ! grep -q 'export PATH="$HOME/.local/bin:$PATH"' ~/.zshrc 2>/dev/null; then
    echo 'export PATH="$HOME/.local/bin:$PATH"' >> ~/.zshrc
fi

# Add aliases
ALIASES='
# Claude Code aliases
alias ccyolo="claude --dangerously-skip-permissions"

# Basic aliases
alias ll="ls -la"
alias la="ls -A"
alias ..="cd .."
alias ...="cd ../.."

# Git aliases
alias gs="git status"
alias gd="git diff"
alias gl="git log --oneline -20"
alias gp="git pull"
'

echo "$ALIASES" >> ~/.bashrc 2>/dev/null || true
echo "$ALIASES" >> ~/.zshrc 2>/dev/null || true

# -----------------------------------------------------------------------------
# Environment Verification
# -----------------------------------------------------------------------------
log "Verifying environment..."

echo ""
echo "=== {{PROJECT_NAME}} Claude Code Environment ==="
echo ""

if command -v claude &> /dev/null; then
    echo "Claude Code: $(claude --version 2>/dev/null || echo 'installed')"
elif [[ -x "$HOME/.local/bin/claude" ]]; then
    echo "Claude Code: installed (in ~/.local/bin)"
fi

if command -v git &> /dev/null; then
    echo "Git: $(git --version)"
fi

if command -v node &> /dev/null; then
    echo "Node.js: $(node --version)"
fi

echo ""
echo "============================================"
echo ""
echo "To start using Claude Code:"
echo "  claude"
echo ""
echo "Or with skip permissions:"
echo "  ccyolo"
echo ""

log "Minimal Claude Code setup complete!"
